import React, { useEffect, useRef, useState } from 'react';
import Quagga from 'quagga';

function BarcodeScanner({ onScan, onError }) {
  const scannerRef = useRef(null);
  const quaggaStarted = useRef(false);
  const scanLock = useRef(false);
  const [active, setActive] = useState(false);

  useEffect(() => {
    if (!active || quaggaStarted.current) return;

    Quagga.init(
      {
        inputStream: {
          type: 'LiveStream',
          target: scannerRef.current,
          constraints: {
            facingMode: 'environment',
            width: { ideal: 640 },
            height: { ideal: 480 }
          }
        },
        locator: {
          patchSize: 'medium',
          halfSample: true
        },
        decoder: {
          readers: ['code_128_reader', 'ean_reader', 'ean_8_reader']
        },
        locate: true
      },
      (err) => {
        if (err) {
          console.error(err);
          onError?.('Camera failed to start');
          return;
        }

        Quagga.start();
        quaggaStarted.current = true;
      }
    );

    Quagga.onDetected((data) => {
      if (scanLock.current) return;

      scanLock.current = true;
      const code = data.codeResult.code;

      // 🛑 STOP CAMERA BEFORE STATE CHANGE
      Quagga.stop();
      quaggaStarted.current = false;

      setTimeout(() => {
        onScan(code);
        scanLock.current = false;
        setActive(false);
      }, 200);
    });

    return () => {
      if (quaggaStarted.current) {
        Quagga.stop();
        quaggaStarted.current = false;
      }
      Quagga.offDetected();
    };
  }, [active, onScan, onError]);

  return (
    <div>
      <button
        className="scan-btn"
        onClick={() => setActive((v) => !v)}
      >
        {active ? 'Stop Scanner' : 'Start Scanner'}
      </button>

      {active && (
        <div
          ref={scannerRef}
          style={{
            width: '100%',
            height: '260px',
            marginTop: '10px',
            borderRadius: '12px',
            overflow: 'hidden'
          }}
        />
      )}
    </div>
  );
}

export default BarcodeScanner;
